# Generate the gateway environment configuration file on first start.
#
# Called from the systemd ExecStartPre directive to bootstrap the
# gateway configuration. Idempotent: exits immediately if the file
# already exists.
#
# Usage:
#   init-gateway-env.sh <env-file>
#
# The generated file contains an auto-generated SSH handshake secret
# and commented defaults for all gateway environment variables.

set -euo pipefail

ENV_FILE="${1:?Usage: init-gateway-env.sh <env-file>}"

# ── Idempotent: skip if env file already exists ─────────────────────
if [ -f "${ENV_FILE}" ]; then
    exit 0
fi

# ── Create parent directory ─────────────────────────────────────────
mkdir -p "$(dirname "${ENV_FILE}")"

# ── Generate SSH handshake secret ───────────────────────────────────
SECRET=$(od -An -tx1 -N32 /dev/urandom | tr -dc 0-9a-f)

# ── Write environment file ──────────────────────────────────────────
cat > "${ENV_FILE}" << EOF
# OpenShell Gateway Environment Configuration
# Generated on first start. Edit freely; this file is not overwritten.
#
# Run 'openshell-gateway --help' for the full list of options.
# See /usr/share/doc/openshell-gateway/ for guides.

# ---- Required ----

# Shared secret for gateway-to-sandbox SSH handshake authentication.
# Auto-generated on first start. To regenerate:
#   openssl rand -hex 32
OPENSHELL_SSH_HANDSHAKE_SECRET=${SECRET}

# ---- Optional (uncomment to override defaults) ----

# Database URL for gateway state persistence.
# Default for the user unit: sqlite://\$XDG_STATE_HOME/openshell/gateway.db
#OPENSHELL_DB_URL=sqlite:///path/to/gateway.db

# Compute driver: podman (default for RPM), docker, kubernetes.
#OPENSHELL_DRIVERS=podman

# Bind address. 0.0.0.0 listens on all interfaces; mTLS prevents
# unauthenticated access.
#OPENSHELL_BIND_ADDRESS=0.0.0.0

# API port (default: 8080).
#OPENSHELL_SERVER_PORT=8080

# Log level: trace, debug, info, warn, error.
#OPENSHELL_LOG_LEVEL=info

# ---- Images ----

# Supervisor binary OCI image (mounted read-only into sandboxes).
#OPENSHELL_SUPERVISOR_IMAGE=ghcr.io/nvidia/openshell/supervisor:latest

# Default sandbox base image.
#OPENSHELL_SANDBOX_IMAGE=ghcr.io/nvidia/openshell-community/sandboxes/base:latest

# Image pull policy: always, missing (default), never, newer.
# Use 'always' to pick up new tags automatically.
# Use 'never' for air-gapped environments with pre-loaded images.
#OPENSHELL_SANDBOX_IMAGE_PULL_POLICY=missing

# ---- TLS (mTLS enabled by default) ----
# PKI is auto-generated by init-pki.sh on first start. Client certs are
# placed in ~/.config/openshell/gateways/openshell/mtls/ so the CLI
# discovers them automatically.
#
# To use externally-managed certs, uncomment and edit the paths below.
# To rotate certs, delete ~/.local/state/openshell/tls/ and restart.
# WARNING: Disabling TLS with the default bind address (0.0.0.0) exposes
# the gateway API to the entire network with NO authentication. Only
# disable TLS when behind a TLS-terminating reverse proxy, or restrict
# OPENSHELL_BIND_ADDRESS to 127.0.0.1.
#OPENSHELL_DISABLE_TLS=true

# Server TLS (gateway listens with these certs).
#OPENSHELL_TLS_CERT=\$XDG_STATE_HOME/openshell/tls/server/tls.crt
#OPENSHELL_TLS_KEY=\$XDG_STATE_HOME/openshell/tls/server/tls.key
#OPENSHELL_TLS_CLIENT_CA=\$XDG_STATE_HOME/openshell/tls/ca.crt

# Podman driver: client certs bind-mounted into sandbox containers.
#OPENSHELL_PODMAN_TLS_CA=\$XDG_STATE_HOME/openshell/tls/ca.crt
#OPENSHELL_PODMAN_TLS_CERT=\$XDG_STATE_HOME/openshell/tls/client/tls.crt
#OPENSHELL_PODMAN_TLS_KEY=\$XDG_STATE_HOME/openshell/tls/client/tls.key

# ---- Podman driver ----

# Podman API Unix socket path.
#OPENSHELL_PODMAN_SOCKET=\$XDG_RUNTIME_DIR/podman/podman.sock

# Podman bridge network name for sandbox containers.
#OPENSHELL_NETWORK_NAME=openshell

# Container stop timeout in seconds (SIGTERM then SIGKILL).
#OPENSHELL_STOP_TIMEOUT=10
EOF

chmod 600 "${ENV_FILE}"
echo "Gateway environment generated: ${ENV_FILE}"
